/*
 * MIMD Shared Memory System - OpenMP Implementation
 * Demonstrates parallel processing with shared global address space
 */

#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include <time.h>

#define ARRAY_SIZE 1000000
#define NUM_THREADS 8

// Shared memory - accessible by all processors/threads
int shared_array[ARRAY_SIZE];
int result_array[ARRAY_SIZE];

// Function to initialize array
void initialize_array(int size) {
 #pragma omp parallel for
 for (int i = 0; i < size; i++) {
 shared_array[i] = i + 1;
 result_array[i] = 0;
 }
}

// Parallel processing: each thread processes different data independently
void parallel_process(int size) {
 double start_time, end_time;

 // Set number of threads
 omp_set_num_threads(NUM_THREADS);

 start_time = omp_get_wtime();

 // Each thread executes this block independently on different data
 #pragma omp parallel for schedule(dynamic, 1000)
 for (int i = 0; i < size; i++) {
 // Different instructions on different data (MIMD principle)
 int thread_id = omp_get_thread_num();
 int num_threads = omp_get_num_threads();

 // Each thread processes its portion independently
 // This simulates independent instruction execution on different data
 int local_result = shared_array[i] * 2;

 // Add some thread-specific computation
 if (thread_id % 2 == 0) {
 local_result += 1; // Even threads do extra operation
 } else {
 local_result -= 1; // Odd threads do different operation
 }

 result_array[i] = local_result;
 }

 end_time = omp_get_wtime();

 printf("Processing completed in %.4f seconds\n", end_time - start_time);
 printf("Using %d threads\n", NUM_THREADS);
}

// Demonstrates critical section for synchronized access
void parallel_with_critical(int size) {
 long long total_sum = 0;

 #pragma omp parallel for reduction(+:total_sum)
 for (int i = 0; i < size; i++) {
 total_sum += shared_array[i];
 }

 printf("Total sum (shared memory): %lld\n", total_sum);
}

// Demonstrates cache coherence with shared variable updates
void demonstrate_cache_coherence() {
 int shared_counter = 0;

 printf("\n=== Cache Coherence Demonstration ===\n");

 #pragma omp parallel num_threads(4)
 {
 int thread_id = omp_get_thread_num();

 // Each thread has private copy in its cache
 // Write operations require coherence maintenance
 #pragma omp critical
 {
 shared_counter++;
 printf("Thread %d incremented counter to %d\n", 
 thread_id, shared_counter);
 }
 }

 printf("Final counter value: %d\n", shared_counter);
}

// Load balancing example - distributing work dynamically
void load_balanced_processing(int size) {
 #pragma omp parallel for schedule guided(1000)
 for (int i = 0; i < size; i++) {
 // Simulate varying workload per iteration
 int work = (i % 100) + 1;
 result_array[i] = work * 2;
 }

 printf("Load balanced processing completed\n");
}

int main() {
 printf("=== MIMD Shared Memory System (OpenMP) ===\n");
 printf("Simulating %d processors with shared global memory\n\n", NUM_THREADS);

 // Initialize
 initialize_array(ARRAY_SIZE);
 printf("Initialized array with %d elements\n", ARRAY_SIZE);

 // Parallel processing
 printf("\n--- Parallel Processing ---\n");
 parallel_process(ARRAY_SIZE);

 // Verify some results
 printf("Sample results: arr[0]=%d, arr[100]=%d, arr[1000]=%d\n",
 result_array[0], result_array[100], result_array[1000]);

 // Summation with shared memory
 printf("\n--- Shared Memory Summation ---\n");
 parallel_with_critical(ARRAY_SIZE);

 // Cache coherence demonstration
 demonstrate_cache_coherence();

 // Load balancing
 printf("\n--- Load Balanced Processing ---\n");
 load_balanced_processing(ARRAY_SIZE);

 return 0;
}

