 * COMPILATION: gcc -fopenmp -o mimd_shared mimd_shared.c
 * 
 * KEY CONCEPTS DEMONSTRATED:
 * 1. Shared global memory - all threads access shared_array
 * 2. Independent execution - each thread processes different elements
 * 3. Different instructions - even/odd threads execute different logic
 * 4. Cache coherence - #pragma omp critical ensures proper synchronization
 * 5. Load balancing - dynamic scheduling for varying workloads
 */

/*
 * MIMD Distributed Memory System - MPI Implementation
 * Demonstrates message passing between processors with private address spaces
 */

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>
#include <time.h>
#include <math.h>

#define ARRAY_SIZE 100000

// Each processor has its own local array (private address space)
// No shared memory between processes

// Function to distribute work across processors
void distribute_work(int *local_array, int local_size, int rank, int world_size) {
 // Each processor generates its own local data
 // This represents private memory - no sharing
 srand(time(NULL) + rank);

 for (int i = 0; i < local_size; i++) {
 local_array[i] = (rand() % 100) + 1;
 }

 printf("Processor %d: Initialized %d local elements\n", rank, local_size);
}

// Each processor performs independent computation on its local data
void local_processing(int *local_array, int *result_array, int local_size, int rank) {
 // MIMD: Different processors can execute different instructions
 // Here we demonstrate different operations based on rank

 if (rank % 2 == 0) {
 // Even ranks: compute square
 for (int i = 0; i < local_size; i++) {
 result_array[i] = local_array[i] * local_array[i];
 }
 } else {
 // Odd ranks: compute square root (rounded)
 for (int i = 0; i < local_size; i++) {
 result_array[i] = (int)sqrt(local_array[i]);
 }
 }
}

// Demonstrate explicit message passing (required for distributed memory)
void communicate_results(int *send_buffer, int send_count, int dest, int tag, MPI_Comm comm) {
 MPI_Send(send_buffer, send_count, MPI_INT, dest, tag, comm);
 printf("Processor sent %d elements to processor %d\n", send_count, dest);
}

void receive_results(int *recv_buffer, int recv_count, int source, int tag, MPI_Comm comm) {
 MPI_Status status;
 MPI_Recv(recv_buffer, recv_count, MPI_INT, source, tag, comm, &status);
 printf("Processor received %d elements from processor %d\n", 
 recv_count, status.MPI_SOURCE);
}

// Gather all results to root processor
void gather_all_results(int *local_result, int local_size, int *global_result, MPI_Comm comm) {
 int rank, world_size;
 MPI_Comm_rank(comm, &rank);
 MPI_Comm_size(comm, &world_size);

 // Gather all local results to root (process 0)
 MPI_Gather(local_result, local_size, MPI_INT, 
 global_result, local_size, MPI_INT, 
 0, comm);
}

// Reduce all results (e.g., sum) to root
long long reduce_results(int *local_array, int local_size, MPI_Comm comm) {
 long long local_sum = 0;
 for (int i = 0; i < local_size; i++) {
 local_sum += local_array[i];
 }

 long long global_sum = 0;
 MPI_Reduce(&local_sum, &global_sum, 1, MPI_LONG_LONG, 
 MPI_SUM, 0, comm);

 return global_sum;
}

// All-to-all communication - each processor exchanges with all others
void all_to_all_exchange(int *send_buffer, int *recv_buffer, int local_size, MPI_Comm comm) {
 int rank, world_size;
 MPI_Comm_rank(comm, &rank);
 MPI_Comm_size(comm, &world_size);

 // Each process sends its data to all other processes
 MPI_Alltoall(send_buffer, local_size, MPI_INT,
 recv_buffer, local_size, MPI_INT,
 comm);
}

int main(int argc, char *argv[]) {
 int rank, world_size;
 int local_size;
 int *local_array, *local_result, *global_result;

 // Initialize MPI - required for distributed memory MIMD
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &world_size);

 // Calculate local work distribution
 local_size = ARRAY_SIZE / world_size;

 // Allocate local (private) memory for each processor
 local_array = (int *)malloc(local_size * sizeof(int));
 local_result = (int *)malloc(local_size * sizeof(int));

 if (rank == 0) {
 global_result = (int *)malloc(ARRAY_SIZE * sizeof(int));
 }

 printf("\n=== MIMD Distributed Memory (MPI) ===\n");
 printf("Processor %d of %d starting...\n", rank, world_size);

 // Step 1: Each processor initializes its own local data
 // No sharing - this is private memory
 distribute_work(local_array, local_size, rank, world_size);

 // Synchronize before computation
 MPI_Barrier(MPI_COMM_WORLD);

 // Step 2: Each processor performs independent computation
 // MIMD: Different instructions on different data
 local_processing(local_array, local_result, local_size, rank);

 // Synchronize after computation
 MPI_Barrier(MPI_COMM_WORLD);

 if (rank == 0) {
 printf("\n--- Results Summary ---\n");
 }

 // Step 3: Reduce results (explicit communication required)
 long long total_sum = reduce_results(local_result, local_size, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Sum of all results: %lld\n", total_sum);
 }

 // Step 4: Gather all results to root
 gather_all_results(local_result, local_size, global_result, MPI_COMM_WORLD);

 if (rank == 0) {
 printf("Gathered all %d results\n", ARRAY_SIZE);
 printf("Sample: global[0]=%d, global[100]=%d\n", 
 global_result[0], global_result[100]);
 }

 // Demonstrate point-to-point communication
 if (world_size > 1) {
 if (rank == 0) {
 communicate_results(local_result, 10, 1, 0, MPI_COMM_WORLD);
 } else if (rank == 1) {
 int recv_buffer[10];
 receive_results(recv_buffer, 10, 0, 0, MPI_COMM_WORLD);
 printf("Processor 1 received: %d, %d, %d...\n", 
 recv_buffer[0], recv_buffer[1], recv_buffer[2]);
 }
 }

 // Cleanup
 free(local_array);
 free(local_result);
 if (rank == 0) {
 free(global_result);
 }

 MPI_Finalize();

 return 0;
}

/*
 * COMPILATION: mpicc -o mimd_distributed mimd_distributed.c
 * RUN: mpirun -np 4 ./mimd_distributed
 * 
 * KEY CONCEPTS DEMONSTRATED:
 * 1. Private address space - each process has local_array (not shared)
 * 2. Explicit message passing - MPI_Send/MPI_Recv required for communication
 * 3. Independent execution - each process works on its own data
 * 4. Different instructions - even/odd ranks compute differently
 * 5. Collective operations - MPI_Gather, MPI_Reduce for result aggregation
 * 6. Synchronization - MPI_Barrier ensures coordination
 * 7. No cache coherence needed - each process has private memory
 */
